sql:
SELECT COUNT(*)
FROM promotional_offers
WHERE status = 0;

SELECT segment_name, COUNT(customer_id) AS customer_count
FROM customer_segments
GROUP BY segment_name;

SELECT customer_id, churn_probability
FROM predictive_model
WHERE churn_probability > 0.20;

external_knowledge:
- 'standing on shaky ground' refers to customers who have not yet churned (c.churn = 0) but have high churn probability (> 0.3) and other risk factors;
- 'have not yet fallen' refers to customers whose contracts have not been renewed (cr.renewal_status = 0);
- 'likely to do so' refers to customers with high churn probability (> 0.3) and low satisfaction ratings (< 3);
- 'substantial monthly bills' refers to an average monthly charge greater than $50.
